components.css:
.ds-icon-btn {
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  appearance: none;
  border-radius: 0.375rem;
  border: 1px solid #dadada;
  background-color: transparent;
  color: rgb(113, 128, 150);
  height: 3em;
  min-width: 3em;
  font-size: 1.125rem;
  font-weight: 600;
  transition: all 250ms ease 0s;
  outline: none;
  user-select: none;
  -webkit-tap-highlight-color: transparent;
}
.ds-icon-btn:hover {
  background-color: #dadada;
  transition: background-color 0.8s;
}
.ds-icon-btn:focus-visible {
  outline: 2px solid #84a59d;
  outline-offset: 2px;
}

#ds-navbar {
  display: flex;
  position: fixed;
  right: 0;
  left: 0;
  z-index: 3000;
  align-items: center;
  padding: 6px 6%;
  width: 100vw;
  background: rgba(250, 248, 248, 0.95);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}
.ds-nav-wrapper {
  width: 100%;
  display: flex;
  justify-content: flex-end;
  list-style: none;
  padding: 0;
  margin: 0;
  opacity: 0.75;
}
.ds-nav-item {
  display: inline;
  list-style: none;
  margin: 12px 15px;
}
.ds-nav-item > a {
  font-size: 0.95em;
  color: #3d3d3d;
  text-decoration: none;
  transition: all 0.2s ease;
}
.ds-nav-item > a:hover {
  text-decoration: underline;
  text-decoration-color: #dadada;
  text-decoration-thickness: 2.5px;
  text-underline-offset: 5px;
}
.ds-logo {
  padding-top: 6px;
  width: 30px;
  height: auto;
  transition: 0.4s;
}
.ds-logo:hover {
  opacity: 0.75;
}

.ds-project {
  font-size: 1.1em;
  margin: 0 0 1rem 0;
  border-radius: 5px;
  border: 1px solid #dadada;
  border-top: 2px solid #84a59d;
  padding: 1em 1.5em;
  box-shadow: 0px 14px 28px rgba(27, 33, 48, 0.06), 0 10px 10px rgba(27, 33, 48, 0.02);
  background-color: transparent;
}
.ds-project-btn {
  cursor: pointer;
  display: inline-flex;
  appearance: none;
  align-items: center;
  justify-content: flex-start;
  background-color: transparent;
  border: none;
  padding: 0;
  width: 100%;
  font-size: 1em;
  color: inherit;
  transition: all 250ms ease 0s;
}
.ds-project-btn:hover {
  background-color: transparent;
}
.ds-project-highlight {
  width: 100%;
  display: flex;
  flex-direction: row;
  align-items: center;
}
.ds-project-highlight p b {
  padding-right: 0.3em;
  font-weight: 600;
  color: #141021;
}
.ds-project-highlight p {
  font-weight: 400;
  white-space: nowrap;
}
.ds-chevron {
  margin-left: auto;
  flex-shrink: 0;
}
.ds-project-text > p {
  padding: 1em 0 0 0;
}
.ds-sub-nav {
  list-style: none;
  padding: 1em 0 0 0;
  margin: 0;
}
.ds-sub-nav > li {
  display: inline-block;
  font-family: 'Roboto Mono', monospace;
  font-size: 0.9em;
  font-weight: 400;
  padding-right: 0.5em;
}
.ds-sub-nav > li > a {
  color: #84a59d;
  text-decoration: none;
  transition: all 0.2s ease;
}
.ds-sub-nav > li > a:hover {
  color: #f7adae;
  transition: color 0.7s;
}
.ds-tools {
  list-style: none;
  padding: 1em 0 0 0;
  margin: 0;
}
.ds-tools > li {
  font-size: 0.9em;
  display: inline-block;
  border: none;
  margin-right: 6px;
  margin-bottom: 4px;
  padding: 0.4rem;
  border-radius: 12px;
  color: #faf8f8;
  background-color: #84a59d;
}

.ds-chip-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 4px 6px;
}
.ds-chip {
  font-size: 0.9em;
  display: inline-block;
  border: none;
  padding: 0.4rem;
  border-radius: 12px;
  color: #faf8f8;
  background-color: #84a59d;
  font-family: 'Source Sans Pro', sans-serif;
  line-height: 1.2;
}

.ds-sub-nav-hero {
  list-style: none;
  padding-left: 0;
  margin: 0;
}
.ds-sub-nav-hero > li {
  display: inline-block;
  font-family: 'Roboto Mono', monospace;
  font-size: 1em;
  font-weight: 400;
  color: #141021;
  padding-right: 0.5em;
}
.ds-sub-nav-hero > li > a {
  color: #84a59d;
  text-decoration: none;
  transition: all 0.2s ease;
}
.ds-sub-nav-hero > li > a:hover {
  color: #f7adae;
  transition: color 0.7s;
}
.ds-sub-nav-hero > li > a:focus-visible {
  outline: 2px solid #84a59d;
  outline-offset: 2px;
  border-radius: 2px;
}
